class Solution:
    def maxSubarraySumCircular(self, nums):
        n = len(nums)
        best = nums[0]
        cur = nums[0]
        for x in nums[1:]:
            cur = max(x, cur + x)
            best = max(best, cur)
        # Brute force for circular: try every (start, length) pair
        total = sum(nums)
        for length in range(1, n + 1):
            for start in range(n):
                s = sum(nums[(start + i) % n] for i in range(length))
                best = max(best, s)
        return best

